law_article":"მუხლი 271"},{"text":"რომელი ქმედებაა სსკ-ის 272-ე მუხლის საგანი?","options":["ნარკოტიკული, ახალი ფსიქოაქტიური ან ფსიქოტროპული ნივთიერების მოხმარებაზე დაყოლიება","მკურნალობაზე დაყოლიება","სპორტულ აქტივობაზე დაყოლიება","საგანმანათლებლო კურსზე მიწვევა"],"correct_option":"A","explanation":"272-ე მუხლი ითვალისწინებს ნარკოტიკული საშუალების, მისი ანალოგის, ახალი ფსიქოაქტიური ან ფსიქოტროპული ნივთიერების მოხმარებაზე დაყოლიებას.","law_article":"მუხლი 272"},{"text":"რას მოიცავს სსკ-ის 273-ე მუხლი?","options":["ნარკოტიკული საშუალების, მისი ანალოგის ან პრეკურსორის მცირე ოდენობით უკანონო დამზადებას, შეძენას, შენახვას, გადაზიდვას ან გადაგზავნას, აგრეთვე ნარკოტიკული ან ახალი ფსიქოაქტიური ნივთიერების ექიმის დანიშნულების გარეშე უკანონო მოხმარებას","ნარკოტიკული საშუალების დიდი ოდენობით საერთაშორისო გადაზიდვას","ფარული ლაბორატორიის მოწყობას","კულტურული ფასეულობის გატანას"],"correct_option":"A","explanation":"273-ე მუხლი ეხება ნარკოტიკული საშუალების, მისი ანალოგის ან პრეკურსორის მცირე ოდენობით უკანონო მოქმედებებს და ნარკოტიკული ან ახალი ფსიქოაქტიური ნივთიერების ექიმის დანიშნულების გარეშე უკანონო მოხმარებას.","law_article":"მუხლი 273"},{"text":"რომელ ტრანსპორტს ეხება სსკ-ის 275-ე მუხლი?","options":["რკინიგზის, წყლის, საჰაერო ან საბაგირო ტრანსპორტის მოძრაობის უსაფრთხოების ან ექსპლუატაციის წესს","მხოლოდ მსუბუქი ავტომობილის მოძრაობას","მხოლოდ საზღვაო პორტის რეჟიმს","მხოლოდ ქვეითთა მოძრაობას"],"correct_option":"A","explanation":"275-ე მუხლი ითვალისწინებს რკინიგზის, წყლის, საჰაერო ან საბაგირო ტრანსპორტის მოძრაობის უსაფრთხოების ან ექსპლუატაციის წესის დარღვევას.","law_article":"მუხლი 275"}]$questions$::jsonb)
  loop
    select id into v_question_id
    from public.questions
    where law_id = v_law_id
      and text = r.question->>'text';

    if v_question_id is null then
      select id into v_article_id
      from public.law_articles
      where law_id = v_law_id
        and article_number = regexp_replace(
          r.question->>'law_article',
          '^(მუხლი[[:space:]]+[^,[:space:]]+).*$',
          '\1'
        );

      insert into public.questions (
        category_id, subcategory_id, law_id, primary_law_article_id, text, difficulty,
        explanation, law_name, law_article, source_url, law_version_date,
        needs_review, is_prime, is_published
      )
      values (
        v_category_id, v_subcategory_id, v_law_id, v_article_id,
        r.question->>'text', 'hard', r.question->>'explanation',
        'საქართველოს სისხლის სამართლის კოდექსი', r.question->>'law_article',
        v_source_url, v_version_date, true, false, false
      )
      returning id into v_question_id;

      insert into public.question_options (question_id, option_text, is_correct, sort_order)
      select
        v_question_id,
        option.value,
        case option.ordinality
          when 1 then r.question->>'correct_option' = 'A'
          when 2 then r.question->>'correct_option' = 'B'
          when 3 then r.question->>'correct_option' = 'C'
          when 4 then r.question->>'correct_option' = 'D'
        end,
        option.ordinality
      from jsonb_array_elements_text(r.question->'options') with ordinality as option(value, ordinality);

      if v_article_id is not null then
        insert into public.question_law_articles (question_id, law_article_id, is_primary)
        values (v_question_id, v_article_id, true)
        on conflict (question_id, law_article_id) do nothing;
      end if;
    end if;
  end loop;
end $$;
